/**
 * Betty introspection — show exactly what Betty computes for each function.
 *
 * Usage: npx tsx src/dogfood-betty-introspect.ts [file.ts]
 */

import { resolve, relative } from 'path';
import { analyzePolyglotSource } from './polyglot-bridge';

const filePath = process.argv[2]
  ? resolve(process.argv[2])
  : resolve(import.meta.dirname, 'checkpoint-substrates.ts');

const ROOT = resolve(import.meta.dirname, '..');
const rel = relative(ROOT, filePath);

console.log(`\nBetty introspection: ${rel}\n`);

const result = await analyzePolyglotSource(filePath);

console.log(`Language: ${result.language}`);
console.log(`Functions: ${result.functions.length}`);
console.log(`Errors: ${result.errors.length}`);
if (result.errors.length > 0) {
  for (const e of result.errors) console.log(`  ERR: ${e}`);
}

console.log('\n' + '='.repeat(90));
console.log(
  'Function'.padEnd(35) +
  'b1'.padStart(4) +
  'deficit'.padStart(8) +
  'buley'.padStart(8) +
  'voidDim'.padStart(8) +
  'heat'.padStart(7) +
  'ghost'.padStart(7) +
  'diags'.padStart(6) +
  '  edges'
);
console.log('='.repeat(90));

for (const f of result.functions) {
  const b = f.bettyResult;
  const deficit = b.deficit?.totalDeficit ?? 0;

  // Count edge types from the AST
  const edgeTypes: Record<string, number> = {};
  if (b.ast) {
    for (const edge of b.ast.edges) {
      edgeTypes[edge.type] = (edgeTypes[edge.type] ?? 0) + 1;
    }
  }
  const edgeSummary = Object.entries(edgeTypes)
    .map(([t, c]) => `${t}:${c}`)
    .join(' ');

  console.log(
    f.functionName.padEnd(35) +
    String(b.b1).padStart(4) +
    String(deficit).padStart(8) +
    b.buleyMeasure.toFixed(1).padStart(8) +
    String(b.voidDimensions).padStart(8) +
    b.landauerHeat.toFixed(1).padStart(7) +
    f.ghostMassLedger.ghost_mass.toFixed(1).padStart(7) +
    String(b.diagnostics.length).padStart(6) +
    '  ' + edgeSummary
  );

  // Show diagnostics if any
  for (const d of b.diagnostics) {
    console.log(`    [${d.severity}] ${d.code}: ${d.message}`);
  }
}

// Detailed view of the most complex function
const mostComplex = result.functions.reduce(
  (best, f) => (f.bettyResult.buleyMeasure > best.bettyResult.buleyMeasure ? f : best),
  result.functions[0]
);

if (mostComplex) {
  console.log(`\n${'='.repeat(90)}`);
  console.log(`DETAILED: ${mostComplex.functionName} (highest Buley measure)`);
  console.log('='.repeat(90));

  const b = mostComplex.bettyResult;
  console.log(`  b1 = ${b.b1}`);
  console.log(`  deficit = ${b.deficit?.totalDeficit ?? 0}`);
  if (b.deficit && b.deficit.perNode.size > 0) {
    console.log('  Per-node deficit:');
    for (const [node, def] of b.deficit.perNode) {
      console.log(`    ${node}: ${def}`);
    }
  }
  console.log(`  buleyMeasure = ${b.buleyMeasure}`);
  console.log(`  voidDimensions = ${b.voidDimensions}`);
  console.log(`  landauerHeat = ${b.landauerHeat}`);

  if (b.stability) {
    console.log(`  stability: harrisRecurrent=${b.stability.harrisRecurrent}`);
  }

  if (b.ast) {
    console.log(`  AST: ${b.ast.nodes.size} nodes, ${b.ast.edges.length} edges`);
    const nodeLabels: Record<string, number> = {};
    for (const [, node] of b.ast.nodes) {
      for (const label of node.labels) {
        nodeLabels[label] = (nodeLabels[label] ?? 0) + 1;
      }
    }
    console.log(`  Node labels: ${JSON.stringify(nodeLabels)}`);
  }

  console.log(`\n  GG source (first 500 chars):`);
  console.log('  ' + mostComplex.ggSource.slice(0, 500).replace(/\n/g, '\n  '));

  // Show the ghost mass ledger
  const gm = mostComplex.ghostMassLedger;
  console.log(`\n  Ghost mass ledger:`);
  console.log(`    forked:    ${gm.forked_mass}`);
  console.log(`    live:      ${gm.live_mass}`);
  console.log(`    folded:    ${gm.folded_mass}`);
  console.log(`    vented:    ${gm.vented_mass}`);
  console.log(`    accounted: ${gm.accounted_mass}`);
  console.log(`    ghost:     ${gm.ghost_mass}`);
  console.log(`    leak_debt: ${gm.leak_debt}`);
}
